// Convenient name for the endpoint pointer the ensures repeatedly mentions.
let ep_ptr = pre_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap();

// Domain identities — every dom() coincides between pre, post1 and post2.
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());

assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());

assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());

assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// src_thread_ptr is frame-fixed because src != dst.
assert(pre_self_.thread_dom().contains(src_thread_ptr));
assert(pre_self_.get_thread(src_thread_ptr) =~= post1_self_.get_thread(src_thread_ptr));
assert(pre_self_.get_thread(src_thread_ptr) =~= post2_self_.get_thread(src_thread_ptr));
assert(post1_self_.get_thread(src_thread_ptr) =~= post2_self_.get_thread(src_thread_ptr));

// Procs: bridge through pre. The two ensures use disjoint triggers
// (post1_self_.get_proc vs post2_self_.get_proc); annotate both so the
// proven quantifier fires for the determinism obligation regardless of
// which side triggers it.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// Containers: same disjoint-trigger pattern.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) implies
    post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
}

// Threads other than dst: both posts equal pre. The ensures shares trigger
// pre_self_.get_thread(t_ptr); state both post triggers as well.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != dst_thread_ptr implies
    post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// dst_thread.endpoint_descriptors@: both posts equal pre.update(...).
let updated_eds = pre_self_.get_thread(dst_thread_ptr).endpoint_descriptors@.update(
    dst_endpoint_index as int,
    Some(pre_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap()),
);
assert(post1_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~= updated_eds);
assert(post2_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~= updated_eds);
assert(post1_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~=
    post2_self_.get_thread(dst_thread_ptr).endpoint_descriptors@);

// Endpoints other than ep_ptr: bridge through pre.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != ep_ptr implies
    post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

// Modified endpoint at ep_ptr: pinned fields (owning_threads@, queue,
// queue_state) take the same RHS in both runs.
let inserted_set = pre_self_.get_endpoint(ep_ptr).owning_threads@.insert((dst_thread_ptr, dst_endpoint_index));
assert(post1_self_.get_endpoint(ep_ptr).owning_threads@ == inserted_set);
assert(post2_self_.get_endpoint(ep_ptr).owning_threads@ == inserted_set);
assert(post1_self_.get_endpoint(ep_ptr).owning_threads@ ==
    post2_self_.get_endpoint(ep_ptr).owning_threads@);

assert(post1_self_.get_endpoint(ep_ptr).queue == pre_self_.get_endpoint(ep_ptr).queue);
assert(post2_self_.get_endpoint(ep_ptr).queue == pre_self_.get_endpoint(ep_ptr).queue);
assert(post1_self_.get_endpoint(ep_ptr).queue == post2_self_.get_endpoint(ep_ptr).queue);

// queue_state ensures references post.get_thread(src).endpoint_descriptors@[..].unwrap();
// since src != dst, post.get_thread(src) =~= pre.get_thread(src) so that
// expression collapses to ep_ptr in both runs.
assert(post1_self_.get_thread(src_thread_ptr).endpoint_descriptors@ =~=
    pre_self_.get_thread(src_thread_ptr).endpoint_descriptors@);
assert(post2_self_.get_thread(src_thread_ptr).endpoint_descriptors@ =~=
    pre_self_.get_thread(src_thread_ptr).endpoint_descriptors@);
assert(post1_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap() == ep_ptr);
assert(post2_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap() == ep_ptr);
assert(post1_self_.get_endpoint(ep_ptr).queue_state == pre_self_.get_endpoint(ep_ptr).queue_state);
assert(post2_self_.get_endpoint(ep_ptr).queue_state == pre_self_.get_endpoint(ep_ptr).queue_state);
assert(post1_self_.get_endpoint(ep_ptr).queue_state == post2_self_.get_endpoint(ep_ptr).queue_state);

// Unit results are trivially equal.
assert(r1 == r2);
